('daily-trivias', 'quick-fire', 'Quick Fire', 'Race the clock with our Quick Fire daily trivia — 6 questions, 15 seconds each. New challenge every 24 hours.', 'The Quick Fire challenge is designed for those who think fast under pressure. Featuring a rotating mix of science, history, and pop culture, this high-intensity quiz forces you to rely on your gut instinct. With only 15 seconds per question, it is the ultimate test of cognitive recall and rapid decision-making.', '["Improve cognitive recall speed and mental agility.","Identify core facts across a diverse range of general knowledge topics.","Master the art of performing accurately under strict time constraints."]'::jsonb, '[{"icon":"🔄","title":"How often are new questions available?","answer":"New quick fire trivia questions are available every day. Come back daily for a fresh challenge."},{"icon":"💰","title":"Is the Quick Fire daily quiz free?","answer":"Yes. The quick fire daily trivia quiz is completely free to play with no registration required."},{"icon":"⏱️","title":"How long does a round take?","answer":"Most quick fire daily quizzes take only a few minutes to finish, so they fit easily into a short break."},{"icon":"🎯","title":"What kind of questions will I see?","answer":"You will see a curated mix of quick fire questions designed to be interesting, accessible, and updated regularly."},{"icon":"🏆","title":"Can I replay the quiz?","answer":"Yes. You can replay the quiz to improve your score or challenge yourself again later."},{"icon":"📚","title":"What is the quiz good for?","answer":"It is a quick way to sharpen your knowledge while learning a few new facts along the way."}]'::jsonb, '["science","history","movies"]'::jsonb, '["rapid fire trivia","quick fire trivia","quick trivia quiz","daily trivia"]'::jsonb, '/imgs/daily-trivias/quick-fire.webp', 'Quick Fire', '⚡', 'from-orange-500 to-red-500', true, 1, true ),
('daily-trivias', 'general-knowledge', 'General Knowledge', 'Test your worldly wisdom with 10 free daily general knowledge trivia questions. Refreshed every day.', 'Our General Knowledge daily quiz is a curated journey through the most interesting facts on Earth. We cover everything from obscure historical milestones to the latest scientific breakthroughs. This quiz is perfect for lifelong learners who want to broaden their intellectual horizons and stay sharp on a global scale.', '["Broaden your understanding of global history and current events.","Connect disparate facts between science, culture, and geography.","Build a versatile knowledge base for social and professional settings."]'::jsonb, '[{"icon":"🔄","title":"How often are new questions available?","answer":"New general knowledge trivia questions are available every day. Come back daily for a fresh challenge."},{"icon":"💰","title":"Is the General Knowledge daily quiz free?","answer":"Yes. The general knowledge daily trivia quiz is completely free to play with no registration required."},{"icon":"⏱️","title":"How long does a round take?","answer":"Most general knowledge daily quizzes take only a few minutes to finish, so they fit easily into a short break."},{"icon":"🎯","title":"What kind of questions will I see?","answer":"You will see a curated mix of general knowledge questions designed to be interesting, accessible, and updated regularly."},{"icon":"🏆","title":"Can I replay the quiz?","answer":"Yes. You can replay the quiz to improve your score or challenge yourself again later."},{"icon":"📚","title":"What is the quiz good for?","answer":"It is a quick way to sharpen your knowledge while learning a few new facts along the way."}]'::jsonb, '["science","history","geography"]'::jsonb, '["general knowledge quiz","daily trivia facts","world trivia questions"]'::jsonb, '/imgs/daily-trivias/general-knowledge.webp', 'General Knowledge', '🌎', 'from-blue-500 to-cyan-500', true, 2, true ),
('daily-trivias', 'today-in-history', 'Today in History', 'Discover what happened on this day in history — free daily trivia with 10 questions on famous birthdays and milestones.', 'Every day is an anniversary of something monumental. This daily history quiz dives into the archives to bring you the battles, discoveries, and births that happened on this exact calendar date. It is a unique way to contextualize the modern world by understanding the specific events that shaped it over centuries.', '["Identify pivotal historical milestones that occurred on today''s date.","Understand the chronological connection between past and present.","Learn about influential figures and their contributions to global history."]'::jsonb, '[{"icon":"🔄","title":"How often are new questions available?","answer":"New today in history trivia questions are available every day. Come back daily for a fresh challenge."},{"icon":"💰","title":"Is the Today in History daily quiz free?","answer":"Yes. The today in history daily trivia quiz is completely free to play with no registration required."},{"icon":"⏱️","title":"How long does a round take?","answer":"Most today in history daily quizzes take only a few minutes to finish, so they fit easily into a short break."},{"icon":"🎯","title":"What kind of questions will I see?","answer":"You will see a curated mix of today in history questions designed to be interesting, accessible, and updated regularly."},{"icon":"🏆","title":"Can I replay the quiz?","answer":"Yes. You can replay the quiz to improve your score or challenge yourself again later."},{"icon":"📚","title":"What is the quiz good for?","answer":"It is a quick way to sharpen your knowledge while learning a few new facts along the way."}]'::jsonb, '["history","famous-quotes","inventions"]'::jsonb, '["historical trivia quiz","on this day trivia","history facts game"]'::jsonb, '/imgs/daily-trivias/today-in-history.webp', 'Today in History', '📅', 'from-amber-500 to-orange-500', true, 3, true ),
('daily-trivias', 'entertainment', 'Entertainment', 'Daily entertainment trivia — movies, music, TV shows, and celebrity questions. 10 free questions refreshed every 24 hours.', 'Stay updated with the world of glitz and glamour. Our entertainment daily quiz tracks the evolution of cinema, the biggest hits on the music charts, and the legends of the small screen. From Hollywood’s Golden Age to the latest viral streaming sensations, we test your grasp of the arts and media.', '["Track the evolution of film, television, and musical trends.","Identify award-winning performances and iconic pop culture moments.","Understand the impact of media on modern society and fashion."]'::jsonb, '[{"icon":"🔄","title":"How often are new questions available?","answer":"New entertainment trivia questions are available every day. Come back daily for a fresh challenge."},{"icon":"💰","title":"Is the Entertainment daily quiz free?","answer":"Yes. The entertainment daily trivia quiz is completely free to play with no registration required."},{"icon":"⏱️","title":"How long does a round take?","answer":"Most entertainment daily quizzes take only a few minutes to finish, so they fit easily into a short break."},{"icon":"🎯","title":"What kind of questions will I see?","answer":"You will see a curated mix of entertainment questions designed to be interesting, accessible, and updated regularly."},{"icon":"🏆","title":"Can I replay the quiz?","answer":"Yes. You can replay the quiz to improve your score or challenge yourself again later."},{"icon":"📚","title":"What is the quiz good for?","answer":"It is a quick way to sharpen your knowledge while learning a few new facts along the way."}]'::jsonb, '["movies","music","tv","celebrities"]'::jsonb, '["pop culture trivia quiz","movie trivia game","celebrity quiz"]'::jsonb, '/imgs/daily-trivias/entertainment.webp', 'Entertainment', '🎬', 'from-purple-500 to-pink-500', true, 4, true ),
('daily-trivias', 'geography', 'Geography', 'Free daily geography trivia — countries, capitals, flags, and world landmarks. 10 fresh questions every day.', 'Explore the world without leaving your home. Our daily geography challenge goes beyond simple capitals to explore tectonic shifts, climatic zones, and cultural landmarks. It is designed to help you visualize the planet and understand the physical and political borders that define our global community.', '["Master the locations of countries, capitals, and major landmarks.","Identify the physical features and biomes of different continents.","Understand the demographic and political shifts in global geography."]'::jsonb, '[{"icon":"🔄","title":"How often are new questions available?","answer":"New geography trivia questions are available every day. Come back daily for a fresh challenge."},{"icon":"💰","title":"Is the Geography daily quiz free?","answer":"Yes. The geography daily trivia quiz is completely free to play with no registration required."},{"icon":"⏱️","title":"How long does a round take?","answer":"Most geography daily quizzes take only a few minutes to finish, so they fit easily into a short break."},{"icon":"🎯","title":"What kind of questions will I see?","answer":"You will see a curated mix of geography questions designed to be interesting, accessible, and updated regularly."},{"icon":"🏆","title":"Can I replay the quiz?","answer":"Yes. You can replay the quiz to improve your score or challenge yourself again later."},{"icon":"📚","title":"What is the quiz good for?","answer":"It is a quick way to sharpen your knowledge while learning a few new facts along the way."}]'::jsonb, '["history","animals","science"]'::jsonb, '["geography trivia quiz","world capitals game","countries trivia"]'::jsonb, '/imgs/daily-trivias/geography.webp', 'Geography', '🗺️', 'from-green-500 to-emerald-500', true, 5, true ),
('daily-trivias', 'science', 'Science & Nature', 'Daily science and nature trivia — biology, physics, space exploration, and the animal kingdom.', 'Unlock the mysteries of the universe with our daily science quiz. Whether we are discussing the microscopic world of cellular biology or the vast expanses of quantum physics and astronomy, these questions are designed to stimulate your curiosity and explain the mechanics of the natural world.', '["Comprehend fundamental laws of physics and chemical reactions.","Explore the diversity of the animal kingdom and Earth''s ecosystems.","Learn about the latest breakthroughs in space exploration and technology."]'::jsonb, '[{"icon":"🔄","title":"How often are new questions available?","answer":"New science & nature trivia questions are available every day. Come back daily for a fresh challenge."},{"icon":"💰","title":"Is the Science & Nature daily quiz free?","answer":"Yes. The science & nature daily trivia quiz is completely free to play with no registration required."},{"icon":"⏱️","title":"How long does a round take?","answer":"Most science & nature daily quizzes take only a few minutes to finish, so they fit easily into a short break."},{"icon":"🎯","title":"What kind of questions will I see?","answer":"You will see a curated mix of science & nature questions designed to be interesting, accessible, and updated regularly."},{"icon":"🏆","title":"Can I replay the quiz?","answer":"Yes. You can replay the quiz to improve your score or challenge yourself again later."},{"icon":"📚","title":"What is the quiz good for?","answer":"It is a quick way to sharpen your knowledge while learning a few new facts along the way."}]'::jsonb, '["animals","inventions","geography"]'::jsonb, '["science trivia quiz","biology quiz game","physics trivia questions"]'::jsonb, '/imgs/daily-trivias/science.webp', 'Science & Nature', '🔬', 'from-cyan-500 to-blue-500', true, 6, true ),
('daily-trivias', 'arts-literature', 'Arts & Literature', 'Free daily arts and literature trivia — great authors, artists, famous paintings, and classic books.', 'Feed your soul with our daily arts and literature trivia. We explore the brushstrokes of Renaissance masters and the profound prose of Nobel-winning authors. This quiz challenges you to recognize the creative milestones that have defined human expression across centuries and cultures.', '["Recognize the stylistic differences between major art movements.","Identify the themes and authors of world-renowned literary classics.","Understand the historical context behind iconic works of art and drama."]'::jsonb, '[{"icon":"🔄","title":"How often are new questions available?","answer":"New arts & literature trivia questions are available every day. Come back daily for a fresh challenge."},{"icon":"💰","title":"Is the Arts & Literature daily quiz free?","answer":"Yes. The arts & literature daily trivia quiz is completely free to play with no registration required."},{"icon":"⏱️","title":"How long does a round take?","answer":"Most arts & literature daily quizzes take only a few minutes to finish, so they fit easily into a short break."},{"icon":"🎯","title":"What kind of questions will I see?","answer":"You will see a curated mix of arts & literature questions designed to be interesting, accessible, and updated regularly."},{"icon":"🏆","title":"Can I replay the quiz?","answer":"Yes. You can replay the quiz to improve your score or challenge yourself again later."},{"icon":"📚","title":"What is the quiz good for?","answer":"It is a quick way to sharpen your knowledge while learning a few new facts along the way."}]'::jsonb, '["literature","arts","famous-quotes"]'::jsonb, '["literature trivia quiz","famous authors quiz","art history questions"]'::jsonb, '/imgs/daily-trivias/arts-literature.webp', 'Arts & Literature', '🎨', 'from-pink-500 to-rose-500', true, 7, true ),
('daily-trivias', 'sports', 'Sports', 'Daily sports trivia — athletes, records, championships, and iconic sporting moments. 10 free questions refreshed every 24 hours.', 'For the ultimate sports fan, this daily quiz is your playing field. We cover the strategy of the pitch, the stats of the court, and the legends of the Olympic track. Test your knowledge of record-breaking performances and the history of global competitions from football to tennis.', '["Recall major sports records, championships, and iconic moments.","Identify the career achievements of legendary athletes.","Understand the rules and historical origins of various global sports."]'::jsonb, '[{"icon":"🔄","title":"How often are new questions available?","answer":"New sports trivia questions are available every day. Come back daily for a fresh challenge."},{"icon":"💰","title":"Is the Sports daily quiz free?","answer":"Yes. The sports daily trivia quiz is completely free to play with no registration required."},{"icon":"⏱️","title":"How long does a round take?","answer":"Most sports daily quizzes take only a few minutes to finish, so they fit easily into a short break."},{"icon":"🎯","title":"What kind of questions will I see?","answer":"You will see a curated mix of sports questions designed to be interesting, accessible, and updated regularly."},{"icon":"🏆","title":"Can I replay the quiz?","answer":"Yes. You can replay the quiz to improve your score or challenge yourself again later."},{"icon":"📚","title":"What is the quiz good for?","answer":"It is a quick way to sharpen your knowledge while learning a few new facts along the way."}]'::jsonb, '["sports","famous-firsts","celebrities"]'::jsonb, '["sports trivia quiz","athlete trivia","sports history game"]'::jsonb, '/imgs/daily-trivias/sports.webp', 'Sports', '⚽', 'from-red-500 to-orange-500', true, 8, true ),
('trivias', 'literature', 'Literature', 'Explore questions about famous books, renowned authors, classic novels, and literary works spanning centuries, from Shakespeare to modern bestsellers.', 'Our literature trivia database spans from the epic poems of Homer to the contemporary masterpieces of the 21st century. Whether you are a fan of Victorian-era prose, Shakespearean drama, or modern psychological thrillers, these questions are designed to test your deep understanding of plot, character development, and literary movements.', '["Identify key themes in Renaissance and Romantic literature.","Recognize the stylistic differences between Prose and Poetry.","Master the chronology of Nobel Prize-winning authors."]'::jsonb, '[]'::jsonb, '["famous-quotes","arts","history"]'::jsonb, '["books","authors","novels","literary quiz"]'::jsonb, '/imgs/categories/literature.webp', 'Literature', null, null, true, 1, true ),
('trivias', 'arts', 'Arts', 'Test your knowledge of visual arts, including painting, sculpture, and architecture, from Renaissance masterpieces to contemporary art movements.', 'Journey through the history of human creativity. This art trivia challenge covers everything from the technical precision of the High Renaissance to the boundary-pushing concepts of Modernism and Pop Art. You will explore the lives of iconic artists and the architectural wonders that define global cities.', '["Distinguish between major art movements like Impressionism and Surrealism.","Identify famous masterpieces and the techniques used to create them.","Understand the historical context of world-renowned architecture."]'::jsonb, '[]'::jsonb, '["literature","fashion","history","cartoons-anime"]'::jsonb, '["art","painting","sculpture","art history"]'::jsonb, '/imgs/categories/arts.webp', 'Arts', null, null, true, 2, true ),
('trivias', 'animals', 'Animals', 'Challenge yourself with questions about wildlife, including mammals, birds, reptiles, and marine life, covering habitats, behaviors, and biology.', 'From the deepest trenches of the ocean to the highest mountain peaks, our animal trivia explores the incredible diversity of Earth''s fauna. Dive into questions about complex ecosystems, fascinating animal behaviors, and the biological traits that allow species to survive in the wild.', '["Classify different species based on biological traits and habitats.","Learn about unique animal survival strategies and migrations.","Understand the importance of biodiversity and conservation efforts."]'::jsonb, '[]'::jsonb, '["science","geography"]'::jsonb, '["animals","wildlife","biology","zoology"]'::jsonb, '/imgs/categories/animals.webp', 'Animals', null, null, true, 3, true ),
('trivias', 'science', 'Science', 'Dive into questions on physics, chemistry, biology, and astronomy, exploring scientific discoveries, theories, and breakthroughs that shape our world.', 'Science is the engine of human progress. This comprehensive trivia set challenges your knowledge of the laws of physics, the building blocks of chemistry, and the mysteries of the cosmos. Discover the stories behind the world''s most famous experiments and the scientists who changed history.', '["Master fundamental concepts in Physics, Chemistry, and Biology.","Identify major scientific breakthroughs and their global impact.","Explore the latest discoveries in Astronomy and Space Exploration."]'::jsonb, '[]'::jsonb, '["animals","technology","geography"]'::jsonb, '["science","physics","chemistry","astronomy"]'::jsonb, '/imgs/categories/science.webp', 'Science', null, null, true, 4, true ),
('trivias', 'history', 'History', 'Answer questions about historical events, influential figures, ancient civilizations, and pivotal moments that have shaped human history across eras.', 'Unlock the secrets of the past. Our history trivia spans ancient empires, the Middle Ages, and the modern political revolutions that define our current world. Test your memory on dates, treaties, and the influential leaders who navigated the tides of time.', '["Recall pivotal dates and events from ancient and modern history.","Understand the rise and fall of major world civilizations.","Analyze the impact of historical figures on contemporary society."]'::jsonb, '[]'::jsonb, '["famous-quotes","literature","arts"]'::jsonb, '["history","historical events","ancient","world history"]'::jsonb, '/imgs/categories/history.webp', 'History', null, null, true, 5, true ),
('trivias', 'geography', 'Geography', 'Test your knowledge of countries, capitals, landmarks, and physical geography, from towering mountains to vast oceans and cultural heritage sites.', 'Become a world traveler from your screen. This geography challenge tests your knowledge of international borders, tectonic plates, and the diverse cultures that inhabit our planet. Whether it''s identifying flags or naming remote mountain ranges, this quiz covers it all.', '["Locate countries, capitals, and major landmarks on a global scale.","Understand physical geography features like climates and biomes.","Explore cultural geography and global demographic trends."]'::jsonb, '[]'::jsonb, '["science","animals"]'::jsonb, '["geography","countries","maps","capitals"]'::jsonb, '/imgs/categories/geography.webp', 'Geography', null, null, true, 6, true ),
('trivias', 'movies', 'Movies', 'Challenge yourself with questions about iconic films, famous actors, directors, and cinema history, from Hollywood blockbusters to indie gems.', 'Step into the spotlight with our cinema trivia. Covering the Golden Age of Hollywood to the latest streaming hits, these questions test your knowledge of Oscar-winning performances, legendary directors, and the behind-the-scenes magic that makes movies unforgettable.', '["Identify iconic films and the directors who created them.","Recall famous movie quotes and award-winning performances.","Explore the evolution of film technology and genres."]'::jsonb, '[]'::jsonb, '["tv","celebrities"]'::jsonb, '["movies","films","hollywood","cinema"]'::jsonb, '/imgs/categories/movies.webp', 'Movies', null, null, true, 7, true ),
('trivias', 'tv', 'TV/Web Series', 'Explore questions about popular television shows, web series, streaming hits, and TV culture, from classic sitcoms to modern binge-worthy dramas.', 'From the era of black-and-white broadcasting to the current ''Peak TV'' streaming revolution, our television trivia celebrates the small screen. Test your knowledge of cult classics, reality TV phenomena, and the complex plots of modern binge-worthy dramas.', '["Master the history of television from its inception to streaming.","Identify key characters and plot twists in popular series.","Understand the cultural impact of major TV events and sitcoms."]'::jsonb, '[]'::jsonb, '["movies","celebrities"]'::jsonb, '["tv","television","series","streaming"]'::jsonb, '/imgs/categories/tv.webp', 'TV/Web Series', null, null, true, 8, true ),
('trivias', 'music', 'Music', 'Test your knowledge of songs, artists, genres, and music history, from classical compositions to modern pop, rock, and hip-hop chart-toppers.', 'Find your rhythm with our extensive music trivia. We dive deep into music theory, the lives of legendary composers, and the chart-topping hits of every decade. Whether you love Rock, Jazz, Classical, or Hip-Hop, there is a challenge here for every ear.', '["Recognize major musical genres and their influential artists.","Learn about music history and the evolution of instruments.","Identify famous lyrics, albums, and legendary composers."]'::jsonb, '[]'::jsonb, '["celebrities"]'::jsonb, '["music","songs","artists","music history"]'::jsonb, '/imgs/categories/music.webp', 'Music', null, null, true, 9, true ),
('trivias', 'celebrities', 'Celebrities', 'Answer questions about famous personalities, including actors, musicians, and influencers, exploring their careers, lives, and cultural impact.', 'Get the inside scoop on the world''s most famous faces. Our celebrity trivia explores the careers, philanthropic efforts, and public lives of icons in film, music, and digital media. See how well you know the stars who define modern pop culture.', '["Track the career milestones of global icons and stars.","Learn about the cultural influence of modern celebrities.","Test your knowledge of famous partnerships and achievements."]'::jsonb, '[]'::jsonb, '["movies","music","tv"]'::jsonb, '["celebrities","pop culture","famous people"]'::jsonb, '/imgs/categories/celebrities.webp', 'Celebrities', null, null, true, 10, true ),
('trivias', 'philosophy', 'Philosophy', 'Challenge yourself with questions about philosophers, schools of thought, ethical dilemmas, and rational ideas that shape human understanding.', 'Engage with the greatest minds in history. This philosophy trivia set poses questions about ethics, metaphysics, and the existential inquiries that have puzzled humanity for millennia. From Socrates to modern thinkers, test your grasp on the theories of existence.', '["Understand major philosophical schools like Stoicism and Existentialism.","Identify famous philosophers and their core arguments.","Explore ethical dilemmas and the foundations of logic."]'::jsonb, '[]'::jsonb, '["history"]'::jsonb, '["philosophy","thought","ethics","logic"]'::jsonb, '/imgs/categories/philosophy.webp', 'Philosophy', null, null, true, 11, true ),
('trivias', 'food', 'Food', 'Explore questions about global cuisines, traditional dishes, culinary techniques, and food culture, from street food to fine dining experiences.', 'Take a bite out of our global food trivia. We explore the origins of classic dishes, the science of cooking techniques, and the unique spices that define regional cuisines. Perfect for foodies and aspiring chefs who want to test their culinary IQ.', '["Identify ingredients and traditional dishes from around the world.","Learn about culinary history and famous chefs.","Master knowledge of cooking methods and food safety."]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["food","cuisine","cooking","culinary"]'::jsonb, '/imgs/categories/food.webp', 'Food', null, null, true, 12, true ),
('trivias', 'sports', 'Sports', 'Test your knowledge of athletes, teams, major sporting events, and sports history, from Olympic records to iconic moments in global competitions.', 'Are you a trivia MVP? Our sports section covers the adrenaline-pumping world of global athletics. From the strategy of the World Cup to the records set at the Olympics, test your knowledge of the teams and legends that make sports history.', '["Recall major sports records and championship histories.","Identify legendary athletes and their career achievements.","Understand the rules and origins of various global sports."]'::jsonb, '[]'::jsonb, '["celebrities","board-games","video-games"]'::jsonb, '["sports","athletes","olympics","teams"]'::jsonb, '/imgs/categories/sports.webp', 'Sports', null, null, true, 13, true ),
('trivias', 'fashion', 'Fashion', 'Answer questions about fashion trends, iconic designers, clothing styles, and the history of fashion, from haute couture to streetwear culture.', 'Walk the virtual runway with our fashion trivia. This category explores the evolution of style, from the structured garments of the Victorian era to the disruptive streetwear of today. Learn about the visionary designers and iconic labels that have defined beauty across generations.', '["Identify influential fashion designers and their signature styles.","Trace the history of fashion trends across different decades.","Understand the impact of cultural movements on clothing and style."]'::jsonb, '[]'::jsonb, '["celebrities"]'::jsonb, '["fashion","designers","style","haute couture"]'::jsonb, '/imgs/categories/fashion.webp', 'Fashion', null, null, true, 14, true ),
('trivias', 'festivals', 'Festivals', 'Explore questions about cultural, religious, and seasonal festivals worldwide, celebrating traditions, holidays, and vibrant global festivities.', 'Celebrate the diversity of human tradition. Our festivals trivia covers the colors of Holi, the lights of Diwali, the lanterns of the Lunar New Year, and the history of Carnival. Discover the origins, foods, and rituals that bring communities together around the globe.', '["Identify major cultural and religious festivals and their meanings.","Learn about unique traditions, foods, and rituals across the world.","Understand the seasonal and historical significance of celebrations."]'::jsonb, '[]'::jsonb, '["geography"]'::jsonb, '["festivals","celebrations","holidays","traditions"]'::jsonb, '/imgs/categories/festivals.webp', 'Festivals', null, null, true, 15, true ),
('trivias', 'business', 'Business', 'Challenge yourself with questions about major companies, global brands, economic principles, and business leaders shaping the corporate world.', 'Step into the boardroom with our business and economics trivia. We examine the rise of tech giants, the strategies of legendary CEOs, and the fundamental economic theories that drive global markets. Test your knowledge of branding, finance, and corporate history.', '["Understand key economic principles and market dynamics.","Identify global brands and the leaders who built them.","Explore the history of industrial revolutions and corporate growth."]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["business","companies","economics","finance"]'::jsonb, '/imgs/categories/business.webp', 'Business', null, null, true, 16, true ),
('trivias', 'acronyms', 'Acronyms', 'Test your knowledge of common and specialized acronyms used in various fields, from technology and business to everyday language.', 'Shorthand is everywhere, but do you know what the letters actually stand for? Our acronyms trivia covers everything from tech jargon and medical terminology to international organizations and slang. Master the language of efficiency across multiple industries.', '["Decode common and specialized acronyms from various industries.","Learn the origins and full names of famous organizations.","Understand the difference between acronyms and initialisms."]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["acronyms","abbreviations","initialisms","jargon"]'::jsonb, '/imgs/categories/acronyms.webp', 'Acronyms', null, null, true, 17, true ),
('trivias', 'languages', 'Languages', 'Explore questions about world languages, linguistic features, language families, and common phrases, from widely spoken tongues to endangered dialects.', 'Linguistics is the study of what makes us human. This trivia category dives into the world''s language families, the history of writing systems, and the curious idioms that make each tongue unique. From the roots of Latin to the complexity of Mandarin, explore how we communicate.', '["Classify major language families and their geographical roots.","Identify common phrases and idioms from different cultures.","Learn about the history and evolution of writing and alphabets."]'::jsonb, '[]'::jsonb, '["geography"]'::jsonb, '["languages","linguistics","phrases","etymology"]'::jsonb, '/imgs/categories/language.webp', 'Languages', null, null, true, 18, true ),
('trivias', 'transportation', 'Transportation', 'Answer questions about various modes of transportation, including cars, trains, airplanes, and ships, exploring their history, technology, and impact on society.', 'From the invention of the wheel to the dawn of space travel, our transportation trivia tracks the movement of humanity. Explore the engineering marvels of locomotives, the history of aviation, and the automotive innovations that have shrunk the world and transformed society.', '["Trace the history and evolution of various modes of transport.","Identify key engineering milestones in aviation and automotive tech.","Understand the social and economic impact of global connectivity."]'::jsonb, '[]'::jsonb, '["geography","science"]'::jsonb, '["transportation","vehicles","travel","aviation"]'::jsonb, '/imgs/categories/transports.webp', 'Transportation', null, null, true, 19, true ),
('trivias', 'famous-firsts', 'Famous Firsts', 'Challenge yourself with questions about groundbreaking achievements and historic ''firsts'' in various fields, from exploration to technology and culture.', 'Celebrate the pioneers who broke the mold. Our ''Famous Firsts'' trivia highlights the individuals and moments that redefined what was possible. From the first person in space to the first woman to win a Nobel Prize, test your knowledge of humanity''s greatest milestones.', '["Identify historic achievements and the pioneers behind them.","Understand the cultural and scientific context of major ''firsts''.","Trace the timeline of groundbreaking discoveries and records."]'::jsonb, '[]'::jsonb, '["history","science"]'::jsonb, '["famous firsts","milestones","pioneers","achievements"]'::jsonb, '/imgs/categories/famous-firsts.webp', 'Famous Firsts', null, null, true, 20, true ),
('trivias', 'religion-spirituality', 'Religion & Spirituality', 'Test your knowledge of world religions, spiritual practices, sacred texts, and religious history, exploring diverse faith traditions from ancient to modern times.', 'Explore the diverse ways humanity seeks meaning. This trivia set covers the sacred texts, holy sites, and core beliefs of major world religions and spiritual paths. Learn about the history of faith, the lives of spiritual leaders, and the rituals that define global cultures.', '["Identify core beliefs and sacred texts of major world religions.","Learn about the historical development of faith traditions.","Understand the cultural significance of religious rituals and sites."]'::jsonb, '[]'::jsonb, '["history","philosophy","festivals"]'::jsonb, '["religion","spirituality","faith","beliefs"]'::jsonb, '/imgs/categories/religion.webp', 'Religion & Spirituality', null, null, true, 21, true ),
('trivias', 'mythology', 'Mythology', 'Explore questions about myths, legends, and folklore from ancient cultures, diving into gods, heroes, and epic tales from global traditions.', 'Enter a world of gods, monsters, and epic heroes. Our mythology trivia dives into the foundational stories of the Greeks, Norse, Egyptians, and beyond. Explore the symbolism and timeless lessons found in the folklore and legends that continue to inspire modern storytelling.', '["Identify gods, heroes, and creatures from various mythologies.","Understand the symbolism and themes in ancient folk tales.","Explore how mythology has influenced art and modern culture."]'::jsonb, '[]'::jsonb, '["history"]'::jsonb, '["mythology","legends","folklore","gods"]'::jsonb, '/imgs/categories/mythology.webp', 'Mythology', null, null, true, 22, true ),
('trivias', 'law-politics', 'Law & Politics', 'Explore questions about legal systems, political ideologies, government structures, and historical political events that shape nations and societies worldwide.', 'How are societies organized and ruled? This category examines the development of legal systems, the clash of political ideologies, and the structure of global governments. Test your knowledge of constitutions, landmark court cases, and the history of diplomacy.', '["Differentiate between various political ideologies and systems.","Understand the structure and functions of global governments.","Identify landmark legal cases and historical political events."]'::jsonb, '[]'::jsonb, '["history","business","famous-quotes"]'::jsonb, '["law","politics","government","constitution"]'::jsonb, '/imgs/categories/law.webp', 'Law & Politics', null, null, true, 23, true ),
('trivias', 'famous-quotes', 'Famous Quotes', 'Challenge yourself with questions about iconic quotes from history, movies, and literature, testing your recall of famous lines and their origins.', 'Words have the power to change the world. Our famous quotes trivia tests your memory of the most influential lines ever spoken or written. From political speeches and literary prose to iconic movie dialogue, see if you can identify the authors and the context of these timeless words.', '["Recall iconic quotes from history, film, and literature.","Identify the authors and speakers of famous lines.","Understand the historical or narrative context of key phrases."]'::jsonb, '[]'::jsonb, '["movies","literature","history","celebrities"]'::jsonb, '["famous quotes","movie lines","quotes"]'::jsonb, '/imgs/categories/famous-quotes.webp', 'Famous Quotes', null, null, true, 24, true ),
('trivias', 'inventions', 'Inventions', 'Test your knowledge of groundbreaking inventions, everyday items, and the stories behind common objects that shape our daily lives and modern society.', 'Discover the genius behind the mundane. This trivia set explores the origins of inventions we take for granted, from the zipper and the lightbulb to the complex technology of the smartphone. Learn about the ''accidental'' discoveries and determined inventors who revolutionized daily life.', '["Identify key inventors and their groundbreaking discoveries.","Understand the history and evolution of everyday objects.","Explore how innovation has transformed modern daily life."]'::jsonb, '[]'::jsonb, '["science","history","famous-firsts"]'::jsonb, '["inventions","technology","innovation","objects"]'::jsonb, '/imgs/categories/inventions.webp', 'Inventions', null, null, true, 25, true ),
('trivias', 'cartoons-anime', 'Cartoons & Anime', 'Challenge yourself with questions about animated shows, anime series, iconic characters, and animation history, from classic cartoons to modern anime masterpieces.', 'From Saturday morning classics to high-stakes anime epics, our animation trivia celebrates the art of the draw. Explore the history of legendary studios, the evolution of animation techniques, and the iconic characters that have become global cultural symbols.', '["Identify iconic characters and shows from cartoons and anime.","Trace the history and evolution of animation techniques.","Learn about influential animation studios and creators."]'::jsonb, '[]'::jsonb, '["movies","tv","video-games"]'::jsonb, '["cartoons","anime","animation","animated shows"]'::jsonb, '/imgs/categories/cartoons.webp', 'Cartoons & Anime', null, null, true, 26, true ),
('trivias', 'board-games', 'Board Games', 'Test your knowledge of classic and modern board games, from strategy-based tabletop titles to family-friendly games enjoyed worldwide.', 'Tabletop gaming has a history as old as civilization itself. Our board games trivia covers everything from the ancient strategies of Chess and Go to the modern complexity of Eurogames and deck-builders. Test your knowledge of game mechanics, history, and the rules of the world''s favorites.', '["Recall the history and origins of classic board games.","Identify modern tabletop titles and their mechanics.","Understand the evolution of gaming culture and strategy."]'::jsonb, '[]'::jsonb, '["video-games","sports"]'::jsonb, '["board games","tabletop","games","strategy"]'::jsonb, '/imgs/categories/board-games.webp', 'Board Games', null, null, true, 27, true ),
('trivias', 'video-games', 'Video Games', 'Answer questions about video games, gaming culture, iconic titles, and esports, from retro classics to cutting-edge modern gaming experiences.', 'Level up your knowledge with our video games trivia. We track the industry from the pixelated beginnings of arcade machines and home consoles to the massive open-world epics and competitive esports of today. Test your memory on iconic characters, groundbreaking developers, and gaming history.', '["Identify iconic video game characters and developers.","Trace the evolution of gaming hardware and software.","Understand the rise of esports and global gaming culture."]'::jsonb, '[]'::jsonb, '["board-games","sports"]'::jsonb, '["video games","gaming","esports","retro gaming"]'::jsonb, '/imgs/categories/video-games.webp', 'Video Games', null, null, true, 28, true ),
('trivias', 'computers', 'Computers', 'Test your knowledge of computer history, hardware, software, programming, and internet culture, from early machines to modern computing breakthroughs.', 'Our computers trivia category spans the evolution of computing from room-sized mainframes to cloud-native platforms, smartphones, and AI tools. Expect questions on operating systems, famous pioneers, core hardware concepts, and the software that transformed everyday life.', '["Identify major milestones in computer and internet history.","Understand the basics of hardware, software, and programming concepts.","Recognize influential companies, products, and computing pioneers."]'::jsonb, '[]'::jsonb, '["science","business","video-games"]'::jsonb, '["computers","technology","programming","hardware","software"]'::jsonb, '/imgs/categories/computers.webp', 'Computers', null, null, true, 29, true ),
('trivias', 'economics', 'Economics', 'Challenge yourself with questions about economic theory, markets, trade, money, and the thinkers and institutions that shape the global economy.', 'Economics trivia explores how people, firms, and governments make decisions under scarcity. From inflation and recessions to trade policy, famous economists, and market behavior, this category is built for players who want to test both textbook knowledge and real-world economic intuition.', '["Understand core economic ideas such as supply and demand, inflation, and trade.","Recognize major economists, institutions, and turning points in economic history.","Connect economic principles to business, finance, and public policy."]'::jsonb, '[]'::jsonb, '["business","law-politics","history"]'::jsonb, '["economics","markets","finance","trade","macroeconomics"]'::jsonb, '/imgs/categories/economics.webp', 'Economics', null, null, true, 30, true ),
('trivias', 'architecture', 'Architecture', 'Explore questions about famous buildings, architectural styles, iconic architects, urban design, and landmark structures from around the world.', 'Architecture trivia covers the structures and design movements that define civilizations and skylines. From classical temples and Gothic cathedrals to modernist icons and contemporary skyscrapers, this category blends design history, engineering, and cultural context.', '["Identify major architectural styles, movements, and signature features.","Recognize landmark buildings, cities, and the architects behind them.","Understand how architecture reflects culture, technology, and historical change."]'::jsonb, '[]'::jsonb, '["arts","geography","history"]'::jsonb, '["architecture","buildings","architects","design","landmarks"]'::jsonb, '/imgs/categories/architecture.webp', 'Architecture', null, null, true, 31, true ),
('trivias', 'picture-clues', 'Picture Clues', 'Play a visual trivia challenge powered by image-based questions drawn from across the trivia bank. Every round serves 10 random questions that already include pictures.', 'Picture Clues is a cross-category visual mode rather than a standalone database category. Instead of drawing from one topic, it assembles a fresh set of image-backed trivia questions from across the site, making it ideal for players who want a more visual and unpredictable challenge.', '["Interpret visual hints and connect them to the right answer quickly.","Test your knowledge across multiple categories in one mixed-image round.","Build recall using landmarks, people, objects, and scenes as clues."]'::jsonb, '[]'::jsonb, '["geography","arts","movies","celebrities"]'::jsonb, '["picture clues","image trivia","visual quiz","photo quiz"]'::jsonb, '/imgs/categories/picture-clues.webp', 'Picture Clues', null, null, false, 32, true )
